import { useEffect, useRef } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import '@xterm/xterm/css/xterm.css';
import { X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

function Terminal() {
  const terminalRef = useRef(null);
  const xtermRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (!terminalRef.current) return;

    // Initialize terminal
    const term = new XTerm({
      cursorBlink: true,
      fontSize: 14,
      fontFamily: 'Menlo, Monaco, "Courier New", monospace',
      theme: {
        background: '#1e1e1e',
        foreground: '#d4d4d4',
        cursor: '#ffffff',
        black: '#000000',
        red: '#cd3131',
        green: '#0dbc79',
        yellow: '#e5e510',
        blue: '#2472c8',
        magenta: '#bc3fbc',
        cyan: '#11a8cd',
        white: '#e5e5e5',
        brightBlack: '#666666',
        brightRed: '#f14c4c',
        brightGreen: '#23d18b',
        brightYellow: '#f5f543',
        brightBlue: '#3b8eea',
        brightMagenta: '#d670d6',
        brightCyan: '#29b8db',
        brightWhite: '#e5e5e5'
      }
    });

    const fitAddon = new FitAddon();
    const webLinksAddon = new WebLinksAddon();

    term.loadAddon(fitAddon);
    term.loadAddon(webLinksAddon);
    term.open(terminalRef.current);
    fitAddon.fit();

    xtermRef.current = term;

    // Welcome message
    term.writeln('\x1b[1;32m╔═══════════════════════════════════════════════════════╗\x1b[0m');
    term.writeln('\x1b[1;32m║         Welcome to SikhshaBox Linux Workspace        ║\x1b[0m');
    term.writeln('\x1b[1;32m╚═══════════════════════════════════════════════════════╝\x1b[0m');
    term.writeln('');
    term.writeln('\x1b[1;36mYour containerized Linux environment is ready!\x1b[0m');
    term.writeln('');
    term.writeln('Available commands:');
    term.writeln('  \x1b[1;33mls\x1b[0m      - List files');
    term.writeln('  \x1b[1;33mpwd\x1b[0m     - Print working directory');
    term.writeln('  \x1b[1;33mwhoami\x1b[0m  - Show current user');
    term.writeln('  \x1b[1;33mclear\x1b[0m   - Clear screen');
    term.writeln('  \x1b[1;33mhelp\x1b[0m    - Show this help');
    term.writeln('');

    let currentLine = '';
    let currentDir = '/home/student';

    const prompt = () => {
      term.write(`\x1b[1;32mstudent@sikhshabox\x1b[0m:\x1b[1;34m${currentDir}\x1b[0m$ `);
    };

    prompt();

    // Simple command handler (mock terminal)
    const handleCommand = (cmd) => {
      term.writeln('');
      const command = cmd.trim().toLowerCase();

      switch (command) {
        case 'ls':
          term.writeln('Documents  Downloads  Pictures  Videos  projects');
          break;
        case 'pwd':
          term.writeln(currentDir);
          break;
        case 'whoami':
          term.writeln('student');
          break;
        case 'clear':
          term.clear();
          break;
        case 'help':
          term.writeln('Available commands: ls, pwd, whoami, clear, help');
          break;
        case 'date':
          term.writeln(new Date().toString());
          break;
        case 'uname':
        case 'uname -a':
          term.writeln('Linux sikhshabox 5.15.0 #1 SMP x86_64 GNU/Linux');
          break;
        case '':
          break;
        default:
          term.writeln(`bash: ${command}: command not found`);
          term.writeln('Type "help" for available commands');
      }

      currentLine = '';
      prompt();
    };

    // Handle keyboard input
    term.onData((data) => {
      const code = data.charCodeAt(0);

      if (code === 13) { // Enter
        handleCommand(currentLine);
      } else if (code === 127) { // Backspace
        if (currentLine.length > 0) {
          currentLine = currentLine.slice(0, -1);
          term.write('\b \b');
        }
      } else if (code >= 32) { // Printable characters
        currentLine += data;
        term.write(data);
      }
    });

    // Handle window resize
    const handleResize = () => {
      fitAddon.fit();
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      term.dispose();
    };
  }, []);

  return (
    <div className="fixed inset-0 bg-gray-900 flex flex-col">
      {/* Header */}
      <div className="bg-gray-800 border-b border-gray-700 px-4 py-3 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <div className="flex space-x-2">
            <div className="w-3 h-3 rounded-full bg-red-500"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
            <div className="w-3 h-3 rounded-full bg-green-500"></div>
          </div>
          <h1 className="text-white font-semibold">Terminal - student@sikhshabox</h1>
        </div>
        
        <button
          onClick={() => navigate(-1)}
          className="text-gray-400 hover:text-white transition-colors"
          title="Close Terminal"
        >
          <X size={20} />
        </button>
      </div>

      {/* Terminal */}
      <div className="flex-1 p-4">
        <div 
          ref={terminalRef} 
          className="h-full w-full"
          style={{ height: 'calc(100vh - 64px)' }}
        />
      </div>
    </div>
  );
}

export default Terminal;